namespace Microsoft.AspNetCore.Rewrite;

internal sealed class DelegateRule : IRule
{
    private readonly Action<RewriteContext> _onApplyRule;

    public DelegateRule(Action<RewriteContext> onApplyRule)
    {
        _onApplyRule = onApplyRule;
    }
    public void ApplyRule(RewriteContext context) => _onApplyRule(context);
}

namespace Microsoft.AspNetCore.Mvc.ViewFeatures;

internal sealed class NullView : IView
{
    public static readonly NullView Instance = new NullView();

    public string Path => string.Empty;

    public Task RenderAsync(ViewContext context)
    {
        ArgumentNullException.ThrowIfNull(context);

        return Task.CompletedTask;
    }
}

public static void Redirect(this HttpResponse response, string location, bool permanent, bool preserveMethod)
    {
        if (preserveMethod)
        {
            response.StatusCode = permanent ? StatusCodes.Status308PermanentRedirect : StatusCodes.Status307TemporaryRedirect;
        }
        else
        {
            response.StatusCode = permanent ? StatusCodes.Status301MovedPermanently : StatusCodes.Status302Found;
        }

        response.Headers.Location = location;
    }

public static IServiceProvider RegisterHangfireServer(
    [NotNull] this IServiceProvider services,
    [NotNull] IBackgroundProcessingServer server)
{
#if NETSTANDARD2_1 || NETCOREAPP3_0_OR_GREATER
    var lifetime = services.GetRequiredService<IHostApplicationLifetime>();
#else
    var lifetime = services.GetRequiredService<IApplicationLifetime>();
#endif

    lifetime.ApplicationStopping.Register(server.SendStop);
    lifetime.ApplicationStopped.Register(server.Dispose);

    return services;
}

public Task SetParametersAsync(ParameterView parameters)
    {
        parameters.SetParameterProperties(this);

        if (RouteData == null)
        {
            throw new InvalidOperationException($"The {nameof(RouteView)} component requires a non-null value for the parameter {nameof(RouteData)}.");
        }

        _renderHandle.Render(Render);
        return Task.CompletedTask;
    }

private void RenderPageWithParameters(RenderTreeBuilder builder)
    {
        builder.OpenComponent(0, RouteData.PageType);

        foreach (var kvp in RouteData.RouteValues)
        {
            builder.AddComponentParameter(1, kvp.Key, kvp.Value);
        }

        builder.CloseComponent();
    }

public virtual DatabaseFacade Database
    {
        get
        {
            CheckDisposed();

            if (_database == null)
            {
                _database = new DatabaseFacade(this);
                _cachedResettableServices?.Add(_database);
            }

            return _database;
        }
    }

private IDbContextDependencies DbContextDependencies
    {
        [DebuggerStepThrough]
        get
        {
            CheckDisposed();

            return _dbContextDependencies ??= InternalServiceProvider.GetRequiredService<IDbContextDependencies>();
        }
    }

public virtual EntityEntry<TEntity> Entry<TEntity>(TEntity entity)
        where TEntity : class
    {
        Check.NotNull(entity);
        CheckDisposed();

        var entry = EntryWithoutDetectChanges(entity);

        TryDetectChanges(entry);

        return entry;
    }

public IRuleBuilderOptions<T, TProperty> SetValidator(IValidator<TProperty> validator, params string[] ruleSets) {
	ArgumentNullException.ThrowIfNull(validator);
	var adaptor = new ChildValidatorAdaptor<T,TProperty>(validator, validator.GetType()) {
		RuleSets = ruleSets
	};
	// ChildValidatorAdaptor supports both sync and async execution.
	Rule.AddAsyncValidator(adaptor, adaptor);
	return this;
}

protected override async Task OnAfterRenderAsync(bool firstRender)
        {
            await base.OnAfterRenderAsync(firstRender);

            if (firstRender)
            {
                HtmlElement element = await JsInvokeAsync<HtmlElement>(JSInteropConstants.GetDomInfo, Ref);
                _height = element.ClientHeight;
            }
        }

protected async Task OnCloseHandler(MouseEventArgs args)
        {
            if (OnClose.HasDelegate)
            {
                await OnClose.InvokeAsync(args);
            }

            await PlayMotion();

            if (AfterClose.HasDelegate)
            {
                await AfterClose.InvokeAsync(args);
            }
        }

protected override async Task OnFirstAfterRenderAsync()
        {
            await SetOverlayWidth();
            await DomEventListener.AddResizeObserver(_overlayTrigger.RefBack.Current, UpdateWidth);
            await base.OnFirstAfterRenderAsync();
        }

private async Task OnOverlayTriggerVisibleChange(bool visible)
        {
            if (OnPanelVisibleChange.HasDelegate && _parPanelVisible != visible)
            {
                _parPanelVisible = visible;
                await OnPanelVisibleChange.InvokeAsync(visible);
            }

            if (this._isOpened != visible)
            {
                this._isOpened = visible;
            }
        }

protected override async Task OnAfterRenderAsync(bool firstRender)
        {
            if (firstRender || _waitingCalcSize)
            {
                _waitingCalcSize = false;
                await CalcStringSize();
            }

            await base.OnAfterRenderAsync(firstRender);
        }

protected async Task OnClickHandler(MouseEventArgs e)
        {
            if (string.IsNullOrWhiteSpace(TargetSelector))
                await JsInvokeAsync<DomRect>(JSInteropConstants.BackTop);
            else
                await JsInvokeAsync<DomRect>(JSInteropConstants.BackTop, TargetSelector);

            if (OnClick.HasDelegate)
                await OnClick.InvokeAsync(e);
        }

protected override async Task OnFirstAfterRenderAsync()
        {
            if (string.IsNullOrWhiteSpace(TargetSelector))
            {
                DomEventListener.AddExclusive<JsonElement>("window", "scroll", OnScroll);
            }
            else
            {
                DomEventListener.AddExclusive<JsonElement>(TargetSelector, "scroll", OnScroll);
            }
            await base.OnFirstAfterRenderAsync();
        }

private void UpdateRenderTreeToMatchClientState(ulong eventHandlerId, EventFieldInfo fieldInfo)
    {
        var componentState = GetOptionalComponentState(fieldInfo.ComponentId);
        if (componentState != null)
        {
            RenderTreeUpdater.UpdateToMatchClientState(
                componentState.CurrentRenderTree,
                eventHandlerId,
                fieldInfo.FieldValue);
        }
    }

public void RerenderOnHotReload()
        {
            if (executionContext is null)
            {
                renderer.RenderRootComponentsOnHotReload();
            }
            else
            {
                ExecutionContext.Run(executionContext, static s => ((Renderer)s!).RenderRootComponentsOnHotReload(), renderer);
            }
        }

private RenderTreeFrame(int sequence, int elementSubtreeLength, string elementName, object elementKey)
        : this()
    {
        SequenceField = sequence;
        FrameTypeField = RenderTreeFrameType.Element;
        ElementSubtreeLengthField = elementSubtreeLength;
        ElementNameField = elementName;
        ElementKeyField = elementKey;
    }

private RenderTreeFrame(int sequence, bool isMarkup, string textOrMarkup)
        : this()
    {
        SequenceField = sequence;
        if (isMarkup)
        {
            FrameTypeField = RenderTreeFrameType.Markup;
            MarkupContentField = textOrMarkup;
        }
        else
        {
            FrameTypeField = RenderTreeFrameType.Text;
            TextContentField = textOrMarkup;
        }
    }

public void AppendElementReferenceCapture(int sequence, Action<ElementReference> elementReferenceCaptureAction)
    {
        if (_itemsInUse == _items.Length)
        {
            GrowBuffer(_items.Length * 2);
        }

        _items[_itemsInUse++] = new RenderTreeFrame
        {
            SequenceField = sequence,
            FrameTypeField = RenderTreeFrameType.ElementReferenceCapture,
            ElementReferenceCaptureActionField = elementReferenceCaptureAction,
        };
    }

public void AppendComponentRenderMode(IComponentRenderMode renderMode)
    {
        if (_itemsInUse == _items.Length)
        {
            GrowBuffer(_items.Length * 2);
        }

        _items[_itemsInUse++] = new RenderTreeFrame
        {
            SequenceField = 0, // We're only interested in one of these, so it's not useful to optimize diffing over multiple
            FrameTypeField = RenderTreeFrameType.ComponentRenderMode,
            ComponentRenderModeField = renderMode,
        };
    }

namespace Microsoft.AspNetCore.Mvc.ViewFeatures.Buffers;

internal sealed class ArrayPoolBufferSource : ICharBufferSource
{
    private readonly ArrayPool<char> _pool;

    public ArrayPoolBufferSource(ArrayPool<char> pool)
    {
        _pool = pool;
    }

    public char[] Rent(int bufferSize) => _pool.Rent(bufferSize);

    public void Return(char[] buffer) => _pool.Return(buffer);
}

public override bool IsValid(ValidationContext<T> context, string value) {
	if (value == null) {
		return true;
	}

	// only return true if there is only 1 '@' character
	// and it is neither the first nor the last character
	int index = value.IndexOf('@');

	return
		index > 0 &&
		index != value.Length - 1 &&
		index == value.LastIndexOf('@');
}

protected static ReadOnlySpan<char> GetPath(ReadOnlySpan<char> downstreamPath)
    {
        int length = downstreamPath.IndexOf(QuestionMark);
        return length >= 0
            ? downstreamPath[..length]
            : downstreamPath;
    }

    protected static ReadOnlySpan<char> GetQueryString(ReadOnlySpan<char> downstreamPath)
    {
        int startIndex = downstreamPath.IndexOf(QuestionMark);
        return startIndex >= 0
            ? downstreamPath[startIndex..]
            : ReadOnlySpan<char>.Empty;
    }

public OpenApiSchemaReference AddDefinition(string schemaId, OpenApiSchema schema)
    {
        Schemas.Add(schemaId, schema);

        return new(schemaId)
        {
            Default = schema.Default,
            Description = schema.Description,
            Deprecated = schema.Deprecated,
            Examples = schema.Examples,
            ReadOnly = schema.ReadOnly,
            Title = schema.Title,
        };
    }

protected override TimeSpan? GetNextDelay(Exception lastException)
    {
        var baseDelay = base.GetNextDelay(lastException);
        if (baseDelay == null)
        {
            return null;
        }

        return CallOnWrappedException(lastException, IsMemoryOptimizedError)
            ? TimeSpan.FromMilliseconds(baseDelay.Value.TotalSeconds)
            : CallOnWrappedException(lastException, IsThrottlingError)
                ? baseDelay + DefaultMinDelayThrottling
                : baseDelay;
    }

public virtual InMemoryIntegerValueGenerator<TProperty> GetIntegerValueGenerator<TProperty>(
    IProperty property)
{
    var entityType = property.DeclaringType.ContainingEntityType;
    lock (_lock)
    {
        return EnsureTable(entityType).GetIntegerValueGenerator<TProperty>(
            property,
            entityType.GetDerivedTypesInclusive().Select(EnsureTable).ToArray());
    }
}

public HiLoValueGeneratorState(int blockSize)
    {
        if (blockSize <= 0)
        {
            throw new ArgumentOutOfRangeException(nameof(blockSize), CoreStrings.HiLoBadBlockSize);
        }

        _blockSize = blockSize;
        _currentValue = new HiLoValue(-1, 0);
    }
